const rows = items.map(i => i.json);

if (!rows || rows.length === 0) {
  return [{ json: { statusCode: 404, payload: [] } }];
}

return [{ json: { statusCode: 200, payload: rows } }];

const q = $input.first().json.query || {};
const range = q.range || "All Time";
const alertTypeRaw = q.alert_type;
const userIdRaw = q.userid;
const startDateRaw = q.start_date;
const endDateRaw = q.end_date;

if (!userIdRaw) {
  return [{ json: { statusCode: 400, payload: { error: "Missing required userid parameter" } } }];
}
if (alertTypeRaw === undefined || alertTypeRaw === null || String(alertTypeRaw).trim() === "") {
  return [{ json: { statusCode: 400, payload: { error: "Missing required alert_type parameter" } } }];
}

const userId = Number(userIdRaw);
if (!Number.isFinite(userId)) {
  return [{ json: { statusCode: 400, payload: { error: "userid must be a number" } } }];
}

const alertTypeStr = String(alertTypeRaw).trim();
const isNumericAlertType = /^[0-9]+$/.test(alertTypeStr);

const now = new Date();
let dateFrom = null;
let dateTo = null;

switch (range) {
  case "Last 24 Hours":
  case "Last+24+Hours":
    dateFrom = new Date(now.getTime() - 24 * 60 * 60 * 1000);
    break;
  case "Last 7 Days":
  case "Last+7+Days":
    dateFrom = new Date(now.getTime() - 7 * 24 * 60 * 60 * 1000);
    break;
  case "Last 30 Days":
  case "Last+30+Days":
    dateFrom = new Date(now.getTime() - 30 * 24 * 60 * 60 * 1000);
    break;
  case "custom":
  case "Custom Date Range":
  case "Custom+Date+Range":
    // Parse custom date range
    if (startDateRaw) {
      dateFrom = new Date(startDateRaw + "T00:00:00");
    }
    if (endDateRaw) {
      // Set to end of day (23:59:59)
      dateTo = new Date(endDateRaw + "T23:59:59");
    }
    break;
  default:
    dateFrom = null;
    dateTo = null;
}

let query = `
  SELECT sd.id, sd.time, sd.value,
         COALESCE(a.type, 'No Alert') AS alert_type,
         COALESCE(a.pulses, 0) AS pulses,
         COALESCE(a.intensity, 0) AS intensity,
         COALESCE(a.duration, 0) AS duration,
         COALESCE(a.interval, 0) AS interval,
         sd.userid,
         sd.usecase_id,
         a.vibration_reason AS reason
  FROM public."SensorData" sd
  LEFT JOIN public."Alert" a ON sd.alertid = a.alertid
`;

let where = [];
let params = [];
let p = 1;

// time filter - start date
if (dateFrom) {
  where.push(`sd.time >= $${p++}`);
  params.push(dateFrom.toISOString());
}

// time filter - end date (for custom range)
if (dateTo) {
  where.push(`sd.time <= $${p++}`);
  params.push(dateTo.toISOString());
}

// user filter
where.push(`sd.userid = $${p++}`);
params.push(userId);

// alert filter: by type OR by sensorid
if (isNumericAlertType) {
  where.push(`sd.usecase_id = $${p++}`);
  params.push(Number(alertTypeStr));
} else {
  where.push(`a.type = $${p++}`);
  params.push(alertTypeStr);
}

query += ` WHERE ${where.join(" AND ")} ORDER BY sd.time;`;

return [{
  json: {
    statusCode: 200,
    query,
    params,
    meta: { range, alertTypeRaw: alertTypeStr, interpretedAs: isNumericAlertType ? "sensorid" : "type", dateFrom, dateTo }
  }
}];

const globalData = $getWorkflowStaticData('global');

const monitoringType = globalData.monitoringType ?? "Unknown";

return [{
  json: {
    monitoringType
  }
}];

const globalData = $getWorkflowStaticData('global');
const monitoringType = $input.first().json.body?.monitoringType;

if (!monitoringType || typeof monitoringType !== "string") {
  return [{ json: { statusCode: 400, payload: { error: "Invalid or missing monitoringType" } } }];
}

globalData.monitoringType = monitoringType;

return [{ json: { statusCode: 200, payload: { status: "success", monitoringType } } }];

const rows = items.map(i => i.json);

return [
  {
    json: {
      rows
    }
  }
];

const body = $input.first().json.body || {};

const userId = parseInt(body.userId);
const usecaseId = parseInt(body.usecaseId);

// Validate inputs
if (!userId || isNaN(userId)) {
  return [{
    json: {
      statusCode: 400,
      error: "Missing or invalid userId"
    }
  }];
}

if (!usecaseId || isNaN(usecaseId)) {
  return [{
    json: {
      statusCode: 400,
      error: "Missing or invalid usecaseId"
    }
  }];
}

// Return clean parameters for the database query
return [{
  json: {
    userId: userId,
    usecaseId: usecaseId
  }
}];

const result = $input.first().json;

if (!result || result.length === 0) {
  return [{
    json: {
      statusCode: 404,
      message: "User not found"
    }
  }];
}

return [{
  json: {
    statusCode: 200,
    message: "Use case assigned successfully",
    data: {
      userId: result.userid,
      activeUsecaseId: result.active_usecase_id
    }
  }
}];

const input = $input.first().json;

// Check if this is an error from the database
if (input.code || input.message) {
  // Check if it's a duplicate key error (unique constraint violation)
  if (input.code === '23505' || (input.message && input.message.includes('duplicate key'))) {
    return [{
      json: {
        statusCode: 409,
        error: "A use case with this name already exists"
      }
    }];
  }

  // Other database errors
  return [{
    json: {
      statusCode: 500,
      error: "Failed to create use case: " + (input.message || "Unknown error")
    }
  }];
}

// Success case - format the successful insert result
return [{
  json: {
    statusCode: 201,
    message: "Use case created successfully",
    data: {
      usecaseId: input.usecase_id,
      name: input.name,
      description: input.description
    }
  }
}];

const body = $input.first().json.body || {};

const name = body.name?.trim();
const description = body.description?.trim() || null;

// Validate name is required
if (!name) {
  return [{
    json: {
      statusCode: 400,
      error: "Name is required"
    }
  }];
}

// Validate name length (max 50 chars per your DB schema)
if (name.length > 50) {
  return [{
    json: {
      statusCode: 400,
      error: "Name must be 50 characters or less"
    }
  }];
}

// Return clean parameters
return [{
  json: {
    name: name,
    description: description
  }
}];

