const body = $input.first().json.body || {};
const mappingId = parseInt(body.mappingId);

if (!mappingId || isNaN(mappingId)) {
  return [{
    json: {
      statusCode: 400,
      error: "Missing or invalid mappingId"
    }
  }];
}

return [{
  json: {
    mappingId: mappingId
  }
}];

const result = $input.first().json;

if (!result || Object.keys(result).length === 0) {
  return [{
    json: {
      statusCode: 404,
      message: "Mapping ID not found"
    }
  }];
}

return [{
  json: {
    statusCode: 200,
    message: "Mapping deactivated successfully",
    data: {
      mappingId: result.id,
      sensor: result.sensorname,
      active: result.isactive
    }
  }
}];

const baseline = $input.first().json.measure;
const schedule = $('Get Due Schedules').first().json;

// Tracking object for performance monitoring
const tracking = {
  user_id: schedule.user_id,
  interval_days: schedule.interval_days || 7,
  processed_at: new Date().toISOString(),
  status: 'calculated'
};

if (!baseline) {
  return [{ json: { ...tracking, status: 'skipped', reason: 'No sensor data' } }];
}

const minVal = Math.round(baseline * (1+0.01*$('Get Due Schedules').first().json.trigger_percentage));
const maxVal = minVal + 20;

return [{
  json: {
    ...tracking,
    minvalue: minVal,
    maxvalue: maxVal,
    type: 'HeartRate'
  }
}];

