const usecase = items[0].json.usecase_name;
const params = items[0].json.parameters;

return params.map(p => ({
  json: {
    usecase_name: usecase,
    parameter_name: p.parameter_name,
    parameter_format: p.parameter_format,
    is_required: p.is_required !== undefined ? p.is_required : true,
    description: p.description || ''
  }
}));

return [{
  json: {
    user_id: $json.user_id,
    interval_days: parseInt($json.interval_days) || 7,
    next_run_date: $json.next_run_date || new Date().toISOString(),
    measure_type: $json.measure_type || 'avg',
    trigger_percentage: parseFloat($json.trigger_percentage) || 10.0,
    active: $json.active !== undefined ? $json.active : true
  }
}];

